{"code": "import json

# Load business data with hours
biz_path = var_functions.query_db:12
with open(biz_path) as f:
    businesses = json.load(f)

# Load ratings
rat_path = var_functions.query_db:24
with open(rat_path) as f:
    ratings = json.load(f)

# Convert to list of tuples for faster lookup
rat_dict = {r['gmap_id']: float(r['avg_rating']) for r in ratings}

# Check if open after 6PM
weekdays = {'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday'}

def is_open_after_6pm(hours):
    if not hours or hours == 'None':
        return False
    s = hours.lower()
    if 'open 24 hours' in s:
        return True
    # Check for any evening time on weekdays
    for day in weekdays:
        if day.lower() in s:
            # Look for evening closing times
            for time in ['7pm', '8pm', '9pm', '10pm', '11pm', '12am', '1am', '2am', '3am', '4am', '5am', '6am']:
                if time in s:
                    return True
    return False

# Filter eligible businesses
eligible = []
for biz in businesses:
    if is_open_after_6pm(biz['hours']):
        gmap_id = biz['gmap_id']
        if gmap_id in rat_dict:
            eligible.append({
                'gmap_id': gmap_id,
                'name': biz['name'],
                'hours': biz['hours'],
                'avg_rating': rat_dict[gmap_id]
            })

# Sort by rating
eligible.sort(key=lambda x: x['avg_rating'], reverse=True)
top5 = eligible[:5]

result = []
for biz in top5:
    result.append({
        'name': biz['name'],
        'avg_rating': round(biz['avg_rating'], 2),
        'hours': biz['hours']
    })

print('__RESULT__:')
print(json.dumps(result))"}

